    }
    
    func decryptToString(data: Data) throws -> String {
        let decryptedData = try decrypt(data: data)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw EncryptionError.decryptionFailed
        }
        return string
    }
    
    // MARK: - Hashing
    
    func hashData(_ data: Data) -> String {
        let digest = SHA256.hash(data: data)
        return digest.compactMap { String(format: "%02x", $0) }.joined()
    }
    
    func hashString(_ string: String) -> String {
        let data = Data(string.utf8)
        return hashData(data)
    }
    
    // MARK: - HMAC for Transaction Integrity
    
    func generateHMAC(for data: Data) throws -> Data {
        guard let key = retrieveSymmetricKeyFromKeychain() else {
            throw EncryptionError.keyNotFound
        }
        
        let hmac = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(hmac)
