        }
    }
    
    func saveEncrypted<T: Codable>(_ object: T, forKey key: String) throws {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(object)
        let encryptedData = try encryptionService.encrypt(data: data)
        let hmac = try encryptionService.generateHMAC(for: data)
        
        let securePackage = SecureDataPackage(encryptedData: encryptedData, hmac: hmac)
        let packageData = try encoder.encode(securePackage)
        
        let fileURL = storageURL.appendingPathComponent(key)
        try packageData.write(to: fileURL, options: .completeFileProtection)
    }
    
    func loadEncrypted<T: Codable>(forKey key: String, as type: T.Type) throws -> T {
        let fileURL = storageURL.appendingPathComponent(key)
        let packageData = try Data(contentsOf: fileURL)
        
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        let securePackage = try decoder.decode(SecureDataPackage.self, from: packageData)
        
        let decryptedData = try encryptionService.decrypt(data: securePackage.encryptedData)
        
        let isValid = try encryptionService.verifyHMAC(securePackage.hmac, for: decryptedData)
        guard isValid else {
            throw EncryptionError.integrityCheckFailed
        }
        
        return try decoder.decode(T.self, from: decryptedData)
    }
    
    func deleteData(forKey key: String) throws {
        let fileURL = storageURL.appendingPathComponent(key)
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
