final class TransactionProcessor {
    
    static let shared = TransactionProcessor()
    
    private let secureStorage = SecureStorageService.shared
    private let encryptionService = EncryptionService.shared
    private let dailyTransactionLimit: Decimal = 50000.00
    private let transactionQueue = DispatchQueue(label: "com.bankingapp.transactionQueue", qos: .userInitiated)
    
    private var recentTransactionHashes: Set<String> = []
    
    private init() {}
    
    // MARK: - Transaction Processing
    
    func processTransaction(_ transaction: Transaction, on account: inout Account) -> Result<TransactionResult, TransactionError> {
        var mutableTransaction = transaction
        
        // Validate
        guard account.isActive else {
            mutableTransaction.status = .failed
            return .failure(.accountInactive)
        }
        
        guard transaction.amount > 0 else {
            mutableTransaction.status = .failed
            return .failure(.invalidAmount)
        }
        
        // Duplicate check
        let transactionHash = generateTransactionHash(transaction)
        guard !recentTransactionHashes.contains(transactionHash) else {
            mutableTransaction.status = .failed
            return .failure(.duplicateTransaction)
        }
        
        // Daily limit check
        let todayTotal = calculateDailyTotal(for: account)
        guard todayTotal + transaction.amount <= dailyTransactionLimit else {
            mutableTransaction.status = .failed
            return .failure(.dailyLimitExceeded)
        }
        
        // Process based on type
        switch transaction.type {
        case .deposit:
            return processDeposit(&mutableTransaction, on: &account)
        case .withdrawal:
            return processWithdrawal(&mutableTransaction, on: &account)
        case .transfer:
            return processTransfer(&mutableTransaction, on: &account)
        case .payment:
            return processPayment(&mutableTransaction, on: &account)
        }
    }
    
    private func processDeposit(_ transaction: inout Transaction, on account: inout Account) -> Result<TransactionResult, TransactionError> {
        account.balance += transaction.amount
        transaction.status = .completed
        account.transactions.append(transaction)
        recentTransactionHashes.insert(generateTransactionHash(transaction))
        
        saveAccountSecurely(account)
        logTransaction(transaction)
        
        let result = TransactionResult(
            success: true,
            transaction: transaction,
            message: "Deposit of \(transaction.amount) \(transaction.currency.rawValue) completed successfully.",
            updatedBalance: account.balance
        )
        return .success(result)
    }